changeSet.sql:

CREATE TABLE groups(
    id INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    course SMALLINT NOT NULL CHECK (course >= 1 AND course <= 6),
    number INTEGER NOT NULL,
    speciality VARCHAR(2) NOT NULL CHECK (speciality ~ '[A-Z]+[1-8]')
);


CREATE TABLE departments (
    id INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    name VARCHAR(50) NOT NULL,
    number INTEGER NOT NULL,
    group_id INTEGER NOT NULL REFERENCES groups(id) ON UPDATE CASCADE ON DELETE CASCADE
);


CREATE TABLE lesson_groups(
    lesson_id INTEGER REFERENCES lessons(id) ON UPDATE CASCADE ON DELETE CASCADE,
    group_id INTEGER REFERENCES groups(id) ON UPDATE CASCADE ON DELETE CASCADE,
    UNIQUE(lesson_id, group_id)
);
